// ── Helpers ────────────────────────────────────────────────────────────────
const statusColor = (s) => ({
  "In Progress": COLORS.sky,     "Scheduled": COLORS.blue,   "Pending": COLORS.gold,
  "Completed":   COLORS.success, "Urgent":    COLORS.danger,  "High":    COLORS.gold,
  "Normal":      COLORS.gray,    "Paid":      COLORS.success, "Sent":    COLORS.sky,
  "Overdue":     COLORS.danger,  "On Job":    COLORS.gold,    "En Route":COLORS.sky,
  "Available":   COLORS.success, "Off Today": COLORS.gray,    "Active":  COLORS.success,
  "None":        COLORS.gray,
}[s] || COLORS.gray);

const Badge = ({ label }) => (
  <span style={{
    background: statusColor(label) + "22", color: statusColor(label),
    border: `1px solid ${statusColor(label)}55`,
    borderRadius: 20, padding: "2px 10px",
    fontSize: 11, fontWeight: 700, letterSpacing: 0.4, whiteSpace: "nowrap",
  }}>{label}</span>
);

const KPICard = ({ icon, label, value, sub, color }) => (
  <div style={{
    background: `linear-gradient(135deg, ${COLORS.navyLight} 0%, ${COLORS.navyMid} 100%)`,
    border: `1px solid ${COLORS.navyMid}`, borderRadius: 14,
    padding: "22px 24px", display: "flex", flexDirection: "column", gap: 6,
    flex: 1, minWidth: 160, position: "relative", overflow: "hidden",
  }}>
    <div style={{ position:"absolute", top:-20, right:-20, width:80, height:80, borderRadius:"50%", background:(color||COLORS.blue)+"18" }} />
    <span style={{ fontSize: 22 }}>{icon}</span>
    <div style={{ fontSize: 28, fontWeight: 800, color: COLORS.white, letterSpacing: -0.5 }}>{value}</div>
    <div style={{ fontSize: 12, color: COLORS.grayLight, fontWeight: 600 }}>{label}</div>
    {sub && <div style={{ fontSize: 11, color: color || COLORS.sky, fontWeight: 500 }}>{sub}</div>}
  </div>
);

const SectionHeader = ({ title, action }) => (
  <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:14 }}>
    <h2 style={{ margin:0, fontSize:14, fontWeight:700, color:COLORS.white, letterSpacing:0.8, textTransform:"uppercase" }}>{title}</h2>
    {action && (
      <button onClick={action.fn} style={{
        background: `linear-gradient(135deg, ${COLORS.gold}, ${COLORS.goldLight})`,
        color: COLORS.navy, border:"none", borderRadius:8,
        padding:"6px 14px", fontSize:12, fontWeight:800, cursor:"pointer", letterSpacing:0.3,
      }}>{action.label}</button>
    )}
  </div>
);

const navItems = [
  { id:"dashboard",   icon:"⊞",  label:"Dashboard"    },
  { id:"jobs",        icon:"🔧", label:"Work Orders"  },
  { id:"schedule",    icon:"📅", label:"Schedule"     },
  { id:"customers",   icon:"👥", label:"Customers"    },
  { id:"technicians", icon:"👷", label:"Technicians"  },
  { id:"invoices",    icon:"💵", label:"Invoices"     },
  { id:"reports",     icon:"📊", label:"Reports"      },
];

// ── Main App ───────────────────────────────────────────────────────────────
export default function ARCOApp() {
  const [active, setActive] = useState("dashboard");
  const [sideOpen, setSideOpen] = useState(true);

  return (
    <div style={{ display:"flex", height:"100vh", background:COLORS.navy, fontFamily:"'Inter','Segoe UI',sans-serif", overflow:"hidden", color:COLORS.text }}>

      {/* ── Sidebar ── */}
      <div style={{
        width: sideOpen ? 230 : 64,
        background: `linear-gradient(180deg, #060F1E 0%, ${COLORS.navy} 100%)`,
        borderRight: `1px solid ${COLORS.navyMid}`,
        display:"flex", flexDirection:"column",
        transition:"width 0.25s ease", flexShrink:0, zIndex:10,
      }}>

        {/* Logo area */}
        <div style={{
          padding: sideOpen ? "18px 16px 16px" : "12px 10px",
          borderBottom: `1px solid ${COLORS.navyMid}`,
          display:"flex", alignItems:"center", justifyContent: sideOpen ? "flex-start" : "center",
          minHeight: 90,
        }}>
          <img
            src={`data:image/png;base64,${LOGO_B64}`}
            alt="ARCO Services"
            style={{
              height: sideOpen ? 64 : 42,
              width: "auto",
              filter: "drop-shadow(0 0 10px rgba(21,101,192,0.55))",
              transition: "height 0.25s ease",
              flexShrink: 0,
            }}
          />
          {sideOpen && (
            <div style={{ marginLeft: 10 }}>
              <div style={{ fontSize:18, fontWeight:900, color:COLORS.white, letterSpacing:2, lineHeight:1, fontFamily:"'Oswald',sans-serif" }}>ARCO</div>
              <div style={{ fontSize:9, color:COLORS.sky, fontWeight:700, letterSpacing:3, textTransform:"uppercase" }}>Services · Atmore, AL</div>
            </div>
          )}
          <button onClick={() => setSideOpen(v => !v)} style={{
            marginLeft:"auto", background:"none", border:"none",
            color:COLORS.gray, cursor:"pointer", fontSize:14, padding:0, flexShrink:0,
          }}>{sideOpen ? "◀" : "▶"}</button>
        </div>

        {/* Nav items */}
        <nav style={{ flex:1, padding:"10px 8px", display:"flex", flexDirection:"column", gap:2 }}>
          {navItems.map(item => (
            <button key={item.id} onClick={() => setActive(item.id)} style={{
              display:"flex", alignItems:"center", gap:10,
              padding: sideOpen ? "10px 12px" : "10px 14px",
              borderRadius:10, border:"none", cursor:"pointer",
              background: active===item.id ? `linear-gradient(90deg, ${COLORS.blue}44, transparent)` : "none",
              borderLeft: active===item.id ? `3px solid ${COLORS.gold}` : "3px solid transparent",
              color: active===item.id ? COLORS.white : COLORS.gray,
              fontSize:13, fontWeight: active===item.id ? 700 : 500,
              textAlign:"left", transition:"all 0.15s",
            }}>
              <span style={{ fontSize:16, flexShrink:0 }}>{item.icon}</span>
              {sideOpen && <span style={{ whiteSpace:"nowrap" }}>{item.label}</span>}
            </button>
          ))}
        </nav>

        {/* User footer */}
        <div style={{ padding:"14px 12px", borderTop:`1px solid ${COLORS.navyMid}`, display:"flex", alignItems:"center", gap:10 }}>
          <div style={{
            width:32, height:32, borderRadius:"50%",
            background:`linear-gradient(135deg, ${COLORS.blue}, ${COLORS.navyMid})`,
            display:"flex", alignItems:"center", justifyContent:"center",
            fontSize:12, fontWeight:800, color:COLORS.white, flexShrink:0,
          }}>AD</div>
          {sideOpen && <div>
            <div style={{ fontSize:12, fontWeight:700, color:COLORS.white }}>Admin</div>
            <div style={{ fontSize:10, color:COLORS.gray }}>ARCO Manager</div>
          </div>}
        </div>
      </div>

      {/* ── Main content ── */}
      <div style={{ flex:1, display:"flex", flexDirection:"column", overflow:"hidden" }}>

        {/* Topbar */}
        <div style={{
          height:56, borderBottom:`1px solid ${COLORS.navyMid}`,
          display:"flex", alignItems:"center", padding:"0 24px",
          background:`linear-gradient(90deg, #060F1E, ${COLORS.navy})`,
          gap:16, flexShrink:0,
        }}>
          <div style={{ flex:1, fontSize:13, color:COLORS.grayLight }}>
            <span style={{ color:COLORS.white, fontWeight:700 }}>{navItems.find(n=>n.id===active)?.label}</span>
            <span style={{ margin:"0 8px", color:COLORS.navyMid }}>·</span>
            <span>Tue, March 10, 2026</span>
            <span style={{ margin:"0 8px", color:COLORS.navyMid }}>·</span>
            <span style={{ color:COLORS.sky }}>Greater Atmore Area · 36502</span>
          </div>
          <div style={{
            background:COLORS.navyLight, borderRadius:8, padding:"6px 14px",
            display:"flex", gap:8, alignItems:"center",
            border:`1px solid ${COLORS.navyMid}`, fontSize:12,
          }}>
            <span>🔍</span>
            <input placeholder="Search jobs, customers..." style={{
              background:"none", border:"none", outline:"none",
              color:COLORS.white, fontSize:12, width:180,
            }} />
          </div>
          <div style={{
            position:"relative", width:34, height:34, cursor:"pointer",
            background:COLORS.navyLight, borderRadius:8,
            display:"flex", alignItems:"center", justifyContent:"center",
            border:`1px solid ${COLORS.navyMid}`, fontSize:16,
          }}>
            🔔
            <span style={{ position:"absolute", top:7, right:7, width:7, height:7, borderRadius:"50%", background:COLORS.gold }} />
          </div>
        </div>

        {/* Page */}
        <div style={{ flex:1, overflow:"auto", padding:24 }}>
          {active==="dashboard"   && <DashboardView />}
          {active==="jobs"        && <JobsView />}
          {active==="customers"   && <CustomersView />}
          {active==="technicians" && <TechsView />}
          {active==="invoices"    && <InvoicesView />}
          {active==="schedule"    && <ScheduleView />}
          {active==="reports"     && <ReportsView />}
        </div>
      </div>
    </div>
  );
}

// ── Dashboard ──────────────────────────────────────────────────────────────
function DashboardView() {
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:24 }}>
      <div style={{ display:"flex", gap:14, flexWrap:"wrap" }}>
        <KPICard icon="🔧" label="Jobs Today"         value="6"     sub="2 done · 2 in progress"  color={COLORS.sky}     />
        <KPICard icon="👷" label="Active Techs"        value="4/5"   sub="1 off today"              color={COLORS.success} />
        <KPICard icon="💵" label="Revenue (MTD)"       value="$21.8K" sub="▲ 14% vs last month"    color={COLORS.gold}    />
        <KPICard icon="⚠️" label="Open Invoices"       value="3"     sub="1 overdue"                color={COLORS.danger}  />
        <KPICard icon="🤝" label="Service Agreements"  value="13"    sub="Active contracts"         color={COLORS.goldLight}/>
      </div>

      <div style={{ display:"grid", gridTemplateColumns:"1fr 300px", gap:20 }}>
        {/* Today's jobs */}
        <div style={{ background:COLORS.navyLight, borderRadius:14, padding:20, border:`1px solid ${COLORS.navyMid}` }}>
          <SectionHeader title="Today's Work Orders" action={{ label:"+ New Job", fn:()=>{} }} />
          <table style={{ width:"100%", borderCollapse:"collapse", fontSize:13 }}>
            <thead>
              <tr style={{ color:COLORS.gray, fontSize:11, textTransform:"uppercase", letterSpacing:0.5 }}>
                {["ID","Customer","Type","Tech","Time","Priority","Status"].map(h=>(
                  <th key={h} style={{ textAlign:"left", padding:"6px 10px", fontWeight:600, borderBottom:`1px solid ${COLORS.navyMid}` }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {mockJobs.map(j=>(
                <tr key={j.id} style={{ borderBottom:`1px solid ${COLORS.navyMid}22` }}>
                  <td style={{ padding:"10px 10px", color:COLORS.sky, fontWeight:700 }}>{j.id}</td>
                  <td style={{ padding:"10px 10px", color:COLORS.white, maxWidth:160, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{j.customer}</td>
                  <td style={{ padding:"10px 10px" }}>{j.type}</td>
                  <td style={{ padding:"10px 10px", color:j.tech==="Unassigned"?COLORS.danger:COLORS.text }}>{j.tech}</td>
                  <td style={{ padding:"10px 10px" }}>{j.time}</td>
                  <td style={{ padding:"10px 10px" }}><Badge label={j.priority} /></td>
                  <td style={{ padding:"10px 10px" }}><Badge label={j.status} /></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {/* Tech status */}
        <div style={{ background:COLORS.navyLight, borderRadius:14, padding:20, border:`1px solid ${COLORS.navyMid}` }}>
          <SectionHeader title="Technicians" />
          <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
            {mockTechs.map(t=>(
              <div key={t.name} style={{
                display:"flex", alignItems:"center", gap:10,
                background:COLORS.navyMid+"88", borderRadius:10, padding:"10px 12px",
              }}>
                <div style={{
                  width:34, height:34, borderRadius:"50%",
                  background:`linear-gradient(135deg, ${statusColor(t.status)}55, ${COLORS.navyMid})`,
                  display:"flex", alignItems:"center", justifyContent:"center",
                  fontSize:12, fontWeight:800, color:COLORS.white, flexShrink:0,
                }}>{t.name.split(" ").map(x=>x[0]).join("")}</div>
                <div style={{ flex:1, minWidth:0 }}>
                  <div style={{ fontWeight:700, fontSize:12, color:COLORS.white }}>{t.name}</div>
                  <div style={{ fontSize:10, color:COLORS.gray }}>{t.skill}</div>
                </div>
                <Badge label={t.status} />
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Recent invoices */}
      <div style={{ background:COLORS.navyLight, borderRadius:14, padding:20, border:`1px solid ${COLORS.navyMid}` }}>
        <SectionHeader title="Recent Invoices" action={{ label:"+ New Invoice", fn:()=>{} }} />
        <div style={{ display:"flex", gap:12, flexWrap:"wrap" }}>
          {mockInvoices.map(inv=>(
            <div key={inv.id} style={{
              background:COLORS.navyMid, borderRadius:10, padding:"14px 18px",
              border:`1px solid ${COLORS.navyMid}`, flex:"1 1 160px", minWidth:160,
            }}>
              <div style={{ display:"flex", justifyContent:"space-between", marginBottom:6 }}>
                <span style={{ fontSize:12, color:COLORS.sky, fontWeight:700 }}>{inv.id}</span>
                <Badge label={inv.status} />
              </div>
              <div style={{ fontSize:15, fontWeight:800, color:COLORS.white, marginBottom:4 }}>{inv.amount}</div>
              <div style={{ fontSize:12, color:COLORS.grayLight }}>{inv.customer}</div>
              <div style={{ fontSize:11, color:COLORS.gray, marginTop:4 }}>{inv.date}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

// ── Work Orders ────────────────────────────────────────────────────────────
function JobsView() {
  const [filter, setFilter] = useState("All");
  const statuses = ["All","Pending","Scheduled","In Progress","Completed"];
  const filtered = filter==="All" ? mockJobs : mockJobs.filter(j=>j.status===filter);
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:20 }}>
      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between" }}>
        <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
          {statuses.map(s=>(
            <button key={s} onClick={()=>setFilter(s)} style={{
              padding:"7px 16px", borderRadius:20, border:"none", cursor:"pointer", fontSize:12, fontWeight:700,
              background: filter===s ? `linear-gradient(135deg,${COLORS.gold},${COLORS.goldLight})` : COLORS.navyMid,
              color: filter===s ? COLORS.navy : COLORS.gray,
            }}>{s}</button>
          ))}
        </div>
        <button style={{ background:`linear-gradient(135deg,${COLORS.gold},${COLORS.goldLight})`, color:COLORS.navy, border:"none", borderRadius:8, padding:"8px 18px", fontWeight:800, fontSize:13, cursor:"pointer" }}>
          + New Work Order
        </button>
      </div>
      <div style={{ background:COLORS.navyLight, borderRadius:14, padding:20, border:`1px solid ${COLORS.navyMid}` }}>
        <table style={{ width:"100%", borderCollapse:"collapse", fontSize:13 }}>
          <thead>
            <tr style={{ color:COLORS.gray, fontSize:11, textTransform:"uppercase", letterSpacing:0.5 }}>
              {["ID","Customer","Address","Type","Tech","Time","Priority","Status"].map(h=>(
                <th key={h} style={{ textAlign:"left", padding:"6px 10px", fontWeight:600, borderBottom:`1px solid ${COLORS.navyMid}` }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filtered.map(j=>(
              <tr key={j.id} style={{ borderBottom:`1px solid ${COLORS.navyMid}22` }}>
                <td style={{ padding:"10px 10px", color:COLORS.sky, fontWeight:700 }}>{j.id}</td>
                <td style={{ padding:"10px 10px", color:COLORS.white, fontWeight:600 }}>{j.customer}</td>
                <td style={{ padding:"10px 10px", color:COLORS.gray, fontSize:12 }}>{j.address}</td>
                <td style={{ padding:"10px 10px" }}>{j.type}</td>
                <td style={{ padding:"10px 10px", color:j.tech==="Unassigned"?COLORS.danger:COLORS.text }}>{j.tech}</td>
                <td style={{ padding:"10px 10px" }}>{j.time}</td>
                <td style={{ padding:"10px 10px" }}><Badge label={j.priority} /></td>
                <td style={{ padding:"10px 10px" }}><Badge label={j.status} /></td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

